import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import ReactQuill from 'react-quill';
import 'react-quill/dist/quill.snow.css';
import {
  Save, Download, Star, StarOff, ArrowLeft,
  Sparkles, Loader, Edit3, X, ChevronRight,
} from 'lucide-react';
import toast from 'react-hot-toast';
import { documentsAPI, aiAPI } from '../utils/api';

const AUTOSAVE_DELAY = 3000; // 3 seconds

const quillModules = {
  toolbar: [
    [{ header: [1, 2, 3, false] }],
    ['bold', 'italic', 'underline', 'strike'],
    [{ list: 'ordered' }, { list: 'bullet' }],
    [{ indent: '-1' }, { indent: '+1' }],
    ['link'],
    ['clean'],
  ],
};

const EditorPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [doc, setDoc] = useState(null);
  const [content, setContent] = useState('');
  const [title, setTitle] = useState('');
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(true);
  const [suggestions, setSuggestions] = useState([]);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [editingTitle, setEditingTitle] = useState(false);
  const autosaveTimer = useRef(null);

  // Load document
  useEffect(() => {
    const fetchDoc = async () => {
      try {
        const { data } = await documentsAPI.getById(id);
        setDoc(data.document);
        setContent(data.document.content);
        setTitle(data.document.title);
      } catch {
        toast.error('Document not found.');
        navigate('/documents');
      } finally {
        setLoading(false);
      }
    };
    fetchDoc();
  }, [id, navigate]);

  // Autosave
  const saveDocument = useCallback(async (newContent, newTitle, showToast = false) => {
    if (!id) return;
    setSaving(true);
    try {
      await documentsAPI.update(id, { content: newContent, title: newTitle });
      setSaved(true);
      if (showToast) toast.success('Document saved!');
    } catch {
      toast.error('Failed to save document.');
    } finally {
      setSaving(false);
    }
  }, [id]);

  const handleContentChange = (value) => {
    setContent(value);
    setSaved(false);
    clearTimeout(autosaveTimer.current);
    autosaveTimer.current = setTimeout(() => {
      saveDocument(value, title);
    }, AUTOSAVE_DELAY);
  };

  const handleTitleChange = (e) => {
    setTitle(e.target.value);
    setSaved(false);
    clearTimeout(autosaveTimer.current);
    autosaveTimer.current = setTimeout(() => {
      saveDocument(content, e.target.value);
    }, AUTOSAVE_DELAY);
  };

  const handleManualSave = () => {
    clearTimeout(autosaveTimer.current);
    saveDocument(content, title, true);
  };

  const handleToggleFavorite = async () => {
    try {
      await documentsAPI.update(id, { isFavorite: !doc.isFavorite });
      setDoc(prev => ({ ...prev, isFavorite: !prev.isFavorite }));
      toast.success(doc.isFavorite ? 'Removed from favourites' : 'Added to favourites');
    } catch {
      toast.error('Failed to update favourite.');
    }
  };

  const handleExportPDF = async () => {
    try {
      toast.loading('Preparing PDF...', { id: 'pdf' });
      const res = await documentsAPI.exportPDF(id);
      const url = window.URL.createObjectURL(new Blob([res.data]));
      const a = document.createElement('a');
      a.href = url;
      a.download = `${title.replace(/[^a-z0-9]/gi, '_')}.pdf`;
      a.click();
      window.URL.revokeObjectURL(url);
      toast.success('PDF downloaded!', { id: 'pdf' });
    } catch {
      toast.error('PDF export failed.', { id: 'pdf' });
    }
  };

  const handleGetSuggestions = async () => {
    setLoadingSuggestions(true);
    setShowSuggestions(true);
    try {
      const { data } = await aiAPI.getSuggestions(content, doc?.type);
      setSuggestions(data.suggestions || []);
    } catch {
      toast.error('Failed to get AI suggestions.');
      setShowSuggestions(false);
    } finally {
      setLoadingSuggestions(false);
    }
  };

  if (loading) {
    return (
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '60vh', gap: '12px' }}>
        <div className="spinner" style={{ width: '28px', height: '28px', borderWidth: '3px', borderColor: 'var(--border)', borderTopColor: 'var(--accent)' }} />
        <span style={{ color: 'var(--text-muted)' }}>Loading document...</span>
      </div>
    );
  }

  return (
    <div style={{ height: 'calc(100vh - 64px)', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      {/* Toolbar */}
      <div style={{
        background: 'var(--bg-secondary)',
        borderBottom: '1px solid var(--border)',
        padding: '10px 20px',
        display: 'flex',
        alignItems: 'center',
        gap: '10px',
        flexWrap: 'wrap',
        flexShrink: 0,
      }}>
        {/* Back */}
        <button className="btn btn-ghost" onClick={() => navigate('/documents')} style={{ padding: '6px 10px' }}>
          <ArrowLeft size={16} />
          <span style={{ fontSize: '13px' }}>Docs</span>
        </button>

        <div style={{ width: '1px', height: '28px', background: 'var(--border)' }} />

        {/* Editable Title */}
        <div style={{ flex: 1, minWidth: '200px' }}>
          {editingTitle ? (
            <input
              className="input"
              value={title}
              onChange={handleTitleChange}
              onBlur={() => setEditingTitle(false)}
              onKeyDown={(e) => e.key === 'Enter' && setEditingTitle(false)}
              autoFocus
              style={{ padding: '6px 10px', fontSize: '14px', fontWeight: '700' }}
            />
          ) : (
            <button
              onClick={() => setEditingTitle(true)}
              style={{
                background: 'none', border: 'none', cursor: 'pointer',
                display: 'flex', alignItems: 'center', gap: '6px',
                color: 'var(--text-primary)', fontFamily: 'var(--font)',
              }}
            >
              <span style={{ fontSize: '15px', fontWeight: '700', letterSpacing: '-0.02em' }}>{title}</span>
              <Edit3 size={13} color="var(--text-muted)" />
            </button>
          )}
        </div>

        {/* Status */}
        <div style={{ fontSize: '12px', color: saving ? 'var(--accent-yellow)' : saved ? 'var(--accent-green)' : 'var(--text-muted)' }}>
          {saving ? '● Saving...' : saved ? '✓ Saved' : '○ Unsaved'}
        </div>

        {/* Type Badge */}
        {doc && <span className={`badge badge-${doc.type}`}>{doc.type}</span>}

        <div style={{ width: '1px', height: '28px', background: 'var(--border)' }} />

        {/* Actions */}
        <button className="btn btn-ghost" onClick={handleToggleFavorite} title="Toggle favourite" style={{ padding: '8px' }}>
          {doc?.isFavorite
            ? <Star size={16} fill="var(--accent-yellow)" color="var(--accent-yellow)" />
            : <StarOff size={16} />}
        </button>

        <button className="btn btn-ghost" onClick={handleGetSuggestions} disabled={loadingSuggestions}
          title="Get AI suggestions" style={{ padding: '6px 12px', fontSize: '13px' }}>
          {loadingSuggestions ? <Loader size={14} style={{ animation: 'spin 1s linear infinite' }} /> : <Sparkles size={14} />}
          <span style={{ marginLeft: '4px' }}>AI Tips</span>
        </button>

        <button className="btn btn-secondary" onClick={handleManualSave} disabled={saving}
          style={{ padding: '6px 14px', fontSize: '13px' }}>
          <Save size={14} />
          Save
        </button>

        <button className="btn btn-primary" onClick={handleExportPDF}
          style={{ padding: '6px 14px', fontSize: '13px' }}>
          <Download size={14} />
          Export PDF
        </button>
      </div>

      {/* Body */}
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        {/* Editor */}
        <div style={{ flex: 1, overflow: 'hidden', padding: '20px', display: 'flex', flexDirection: 'column' }}>
          <ReactQuill
            theme="snow"
            value={content}
            onChange={handleContentChange}
            modules={quillModules}
            style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}
          />
        </div>

        {/* AI Suggestions Panel */}
        {showSuggestions && (
          <div style={{
            width: '300px',
            flexShrink: 0,
            background: 'var(--bg-card)',
            borderLeft: '1px solid var(--border)',
            display: 'flex',
            flexDirection: 'column',
            overflow: 'hidden',
          }}>
            <div style={{
              padding: '16px',
              borderBottom: '1px solid var(--border)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
            }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                <Sparkles size={16} color="var(--accent)" />
                <span style={{ fontWeight: '700', fontSize: '14px' }}>AI Suggestions</span>
              </div>
              <button className="btn btn-ghost" onClick={() => setShowSuggestions(false)} style={{ padding: '4px' }}>
                <X size={16} />
              </button>
            </div>

            <div style={{ flex: 1, overflow: 'auto', padding: '16px', display: 'flex', flexDirection: 'column', gap: '10px' }}>
              {loadingSuggestions ? (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                  {[1, 2, 3, 4, 5].map(i => (
                    <div key={i} style={{
                      height: '60px', background: 'var(--bg-input)',
                      borderRadius: 'var(--radius-sm)',
                      animation: 'pulse 1.5s ease infinite',
                    }} />
                  ))}
                </div>
              ) : suggestions.length === 0 ? (
                <p style={{ color: 'var(--text-muted)', fontSize: '13px', textAlign: 'center', padding: '20px 0' }}>
                  No suggestions available. Add more content first.
                </p>
              ) : (
                suggestions.map((s, i) => (
                  <div key={i} style={{
                    background: 'var(--bg-input)',
                    border: '1px solid var(--border)',
                    borderRadius: 'var(--radius-sm)',
                    padding: '12px',
                    display: 'flex',
                    gap: '10px',
                    alignItems: 'flex-start',
                  }}>
                    <div style={{
                      width: '22px', height: '22px', flexShrink: 0,
                      background: 'rgba(108,99,255,0.15)',
                      borderRadius: '50%',
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      fontSize: '11px', fontWeight: '700', color: 'var(--accent)',
                    }}>
                      {i + 1}
                    </div>
                    <p style={{ fontSize: '13px', color: 'var(--text-secondary)', lineHeight: '1.5' }}>{s}</p>
                  </div>
                ))
              )}
            </div>

            {!loadingSuggestions && suggestions.length > 0 && (
              <div style={{ padding: '12px 16px', borderTop: '1px solid var(--border)' }}>
                <button className="btn btn-secondary" onClick={handleGetSuggestions}
                  style={{ width: '100%', justifyContent: 'center', fontSize: '13px' }}>
                  <Sparkles size={14} /> Refresh Suggestions
                </button>
              </div>
            )}
          </div>
        )}
      </div>

      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.5; }
        }
        .ql-editor { min-height: 300px; }
      `}</style>
    </div>
  );
};

export default EditorPage;
